"use client";
import { ConfettiBurst } from "@/components/ui/confetti-burst";
import { useState } from "react";

export default function SignupForm() {
  const [submitted, setSubmitted] = useState(false);

  return (
    <div className="w-full max-w-sm mx-auto p-8 space-y-4">
      {submitted ? (
        <div className="text-center text-white py-8">
          <p className="text-2xl font-bold">You're in! 🎉</p>
          <p className="text-neutral-400 text-sm mt-2">Check your inbox for next steps.</p>
        </div>
      ) : (
        <>
          <input type="email" placeholder="Your email" className="w-full px-4 py-2.5 rounded-xl bg-neutral-900 border border-neutral-700 text-white" />
          <ConfettiBurst className="w-full rounded-xl">
            <button
              onClick={() => setSubmitted(true)}
              className="w-full py-3 bg-purple-600 text-white rounded-xl font-semibold"
            >
              Join waitlist
            </button>
          </ConfettiBurst>
        </>
      )}
    </div>
  );
}

"use client";
import { ConfettiBurst } from "@/components/ui/confetti-burst";
import { useState } from "react";
import { Trophy } from "lucide-react";

export default function AchievementCard() {
  const [unlocked, setUnlocked] = useState(false);

  return (
    <div className="p-6 rounded-2xl border border-neutral-800 bg-neutral-900 text-center space-y-4 max-w-xs mx-auto mt-20">
      <Trophy className={`w-10 h-10 mx-auto transition-colors ${unlocked ? "text-yellow-400" : "text-neutral-600"}`} />
      <p className="text-white font-semibold">First component added</p>
      {!unlocked ? (
        <ConfettiBurst particleCount={80} className="inline-block">
          <button
            onClick={() => setUnlocked(true)}
            className="px-5 py-2 bg-purple-600 text-white rounded-xl text-sm font-medium"
          >
            Claim reward
          </button>
        </ConfettiBurst>
      ) : (
        <p className="text-yellow-400 text-sm font-medium">Achievement unlocked! 🏆</p>
      )}
    </div>
  );
}
